var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"얼른 풀어 주시지 말임다! 저녁 먹기 전에는 돌아가야 함다!","JPN":"はやく放してほしいっす！　晩ご飯の時間になる前に戻らないとまずいっす！","ENG":"Lemme go! I gotta get back before supper!","TWN":"快放開我！我要趕在晚飯前回去！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너 어릴 때 무슨 이터니움 드라이브라도 먹었니? 어떻게 된 게 지치지도 않아?","JPN":"あんたね、子どもの頃エタニウムドライブでも飲み込んだの？　なんで全然疲れないの？","ENG":"Did you swallow an Eternium drive when you were a baby or something? Don't you ever get tired, kid?","TWN":"妳小時候是不是吃了永恆之金引擎？怎麼這麼聒噪啊？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우으...... 그 말을 들었더니 배가 고파졌슴다......","JPN":"うぅ……その話を聞いたらお腹が空いてきたっす……","ENG":"Err... Now you've gotten me all hungry...","TWN":"唔呃……你這麼一說我更餓了……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아주 자기 집 안방이네.","JPN":"あーあ、とんでもないのんき者なんだね。","ENG":"Don't get too comfortable now.","TWN":"妳當這裡是妳家嗎。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"자, 카레라이스야. 내가 연습 삼아 만들었던 건데 이거라도 줄게.","JPN":"さあ、カレーライスよ。練習用に作ったものだけど、あげる。","ENG":"Here, try this curry. I made it for practice, but you can have some.","TWN":"來，這是咖喱，我用來練習的時候嘗試做的，吃吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오오! 착한 언니였지 말임다!","JPN":"おお！　実は優しいお姉さんだったんっすね！","ENG":"Ooh! You're a nice kidnapper, ma'am!","TWN":"哇哇！妳真是個善良的姐姐！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으엑?! 너, 너무 맵슴다! 모네를 매워 죽게 만들려는 게 틀림없슴다아!","JPN":"うおっ！？　か、辛いっす！　激辛カレーでモネを気絶させるつもりっすか？","ENG":"Eeep? I-it's too spicy! You wanna kill Mone with this, don't you?","TWN":"呃啊？！好，好辣啊！妳是不是想辣死莫妮！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"무슨 말도 안 되는 소리야?! 아주 살짝 매콤하게 양념했을 뿐인데!","JPN":"何言ってるの！　ほんの少し辛めに味付けしただけよ！","ENG":"Don't be ridiculous! I just added a little spice for an extra kick!","TWN":"妳在胡說八道什麼？！我只是稍微放了點辣而已！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하여간 맛을 모르는 녀석들이 많다니까.","JPN":"まったく、味覚がおかしいやつばっかりなんだから。","ENG":"People don't appreciate fine cooking these days.","TWN":"妳們這些傢伙，就是不懂得品嚐。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그리고 애초에 네가 음식 투정을 할 입장이야?","JPN":"そもそもあんたさ、文句言える立場じゃないんだよ？","ENG":"Besides, you're in no position to complain about food!","TWN":"而且，妳現在還敢挑食？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"넌 지금 인질로 잡힌 거라고!","JPN":"今、人質として囚われているんだからね！","ENG":"You've been taken hostage!","TWN":"妳現在可是人質！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"히잉......","JPN":"ふえ……","ENG":"Aww...","TWN":"嗚嗚……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그런데 메이드가 왜 납치를 하심까. 납치는 나쁜 사람들이나 하는 범죄이지 말임다.","JPN":"ところでメイドがどうしてこんなことするんっすか？　人さらいは悪い人がする立派な犯罪っすよ？","ENG":"Why would maids kidnap me though? Only bad guys and criminals kidnap people.","TWN":"妳們為什麼要綁架女僕，只有壞人才會綁架別人呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그, 그게 말이지......","JPN":"そ、それは……","ENG":"W-well... You see...","TWN":"那、那是因為……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"주인님의 명령을 따르기 위해서죠.","JPN":"ご主人様の命令に従うためです。","ENG":"We are following our Master's orders.","TWN":"我們要遵從主人的命令。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"리, 릴리. 거래는 잘 됐어?","JPN":"リ、リリー。取引はうまくいったの？","ENG":"L-Lily. How did the deal go?","TWN":"莉、莉莉，交易談好了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네. 다음 전투에 필요한 물자도 추가로 확보했습니다.","JPN":"はい。次の戦闘に必要な物資の追加確保ができました。","ENG":"It went well. I've secured the supplies for our next engagement as well.","TWN":"是的，而且額外籌集到了下次戰鬥時所需的物資。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 교수가 제법 편의를 봐주고 있네요.","JPN":"あの教授がだいぶ協力してくれていますね。","ENG":"The Professor has proven to be quite convenient.","TWN":"那個教授給我們開了個方便。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그보다 저 꼬마, 목소리가 너무 커요.","JPN":"それよりあの子の声が大きすぎます。","ENG":"By the way, the kid is being too loud.","TWN":"不過，那個小孩子的嗓門太大了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"괜히 관심 끌리지 않게 조용히 시키세요. 필요하다면 고문도 허락하겠습니다.","JPN":"人目を引かないよう静かにさせてください。必要ならば拷問も許可します。","ENG":"Keep her quiet or she'll draw unwanted attention. You have permission to torture her if that's what it takes.","TWN":"妳最好讓她小聲點，別引人注意。如果有需要，我允許妳嚴刑拷打她。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"고...... 고문 말임까? 모네는 아픈 거 싫슴다......","JPN":"ご……拷問っすか？　モネは痛いのはイヤっす……","ENG":"T-torture? I don't like pain...","TWN":"拷……拷問？莫妮怕疼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야, 고문이라니 심하잖아. 얘한테서 무슨 정보를 캐내겠다고.","JPN":"ねえ、拷問はひどいでしょう。こんな子どもじゃあ、ろくな情報も持ってないだろうし。","ENG":"Hey, isn't that too harsh? It's not like we can squeeze any intel out of the kid.","TWN":"喂，嚴刑拷打是不是有點過分了，她能知道些什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE","text":{"KOREA":"어째 소란스러운 것 같은데. 내가 연락할 시기를 잘못 골랐나?","JPN":"ちょっと騒がしいようね。連絡のタイミングが悪かったのかしら。","ENG":"What's with all the commotion? Is this a bad time to call?","TWN":"鬧什麼呢，我是不是來得不是時候。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"마, 마스터?","JPN":"マ、マスター？","ENG":"M-Master?","TWN":"頭，頭目？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"아닙니다, 마스터. 무슨 일로 찾으셨나요.","JPN":"いいえ、マスター。いかがなさいましたか。","ENG":"Of course not, Master. How may we serve?","TWN":"怎麼會呢，您怎麼來了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"거슬리는 소식이 들리더구나. 내 꽃들이 배신자를 눈앞에서 놓쳐 버렸다고 말이야.","JPN":"不愉快な噂が聞こえてきてね。うちの花たちが裏切り者を目の前で見逃した、と。","ENG":"I've come across some disturbing news... that my lovely flowers lost the traitor right when they had her.","TWN":"我聽到了一個令我很不爽的消息，聽說我的小花們眼睜睜地讓叛徒溜走了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"나는 분명 배신자를 솎아내라고 했는데...... 어떻게 된 거지?","JPN":"確か裏切り者は間引けと言ったはずなんだけど……どういうことかしら？","ENG":"I thought I made it clear that you must pluck out the traitor... What happened?","TWN":"我明明吩咐過你們，給我除掉叛徒……這到底是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......죄송합니다, 주인님. 매복이 있던 탓에 즉결 처분에는 실패했습니다.","JPN":"……申し訳ございません、ご主人様。待ち伏せに気付かず、即決処分に失敗しました。","ENG":"I'm sorry, Master. An ambush prevented us from putting her down immediately.","TWN":"……對不起，主人。因為那裡有埋伏，所以我們沒能立即處決她。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"하지만 인질은 확보했으니, 조만간......","JPN":"しかし人質を確保しているので、もうじき……","ENG":"But we've secured a hostage. Soon, we will—","TWN":"但我們抓到了人質，遲早……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"죽는 게 두려워서 물러섰단 말을 길게도 늘어 놓는구나.","JPN":"命が惜しくて逃げたという言い訳を、そんな長々と並べていいのかしら。","ENG":"That's a long-winded way of saying you backed down because you were scared of dying.","TWN":"不要找藉口了，妳們不就是怕死嗎。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저는 그 배신자와 다릅니다, 주인님!","JPN":"私はあの裏切り者とは違います、ご主人様！","ENG":"I'm not like the traitor, Master!","TWN":"我和那個叛徒不同，主人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"조금만...... 조금만 더 기다려 주십시오.","JPN":"もう少し……もう少しだけお時間をください。","ENG":"Please... give us a little more time.","TWN":"再……再給我一次機會吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"반드시 좋은 소식을 들고 돌아가겠습니다.","JPN":"必ず喜ばしい報告と共に帰還いたします。","ENG":"We will return with good news, no matter what.","TWN":"我一定會給您帶來好消息的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"그래. 진심인 모양이니 한 번은 눈감아 주마.","JPN":"まあ、本気のようだから今回は許してあげる。","ENG":"Very well. You seem earnest enough. I'll let this one slide.","TWN":"好，看妳如此有誠意，這次就算了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"하지만 기억해 두렴.","JPN":"でも覚えておきなさい。","ENG":"But don't forget.","TWN":"但妳們可別忘了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"두 번 용서는 없어.","JPN":"二度目はないと。","ENG":"There are no more chances.","TWN":"不會再有下一次。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하아...... 깜짝이야.","JPN":"はあ……ビックリした。","ENG":"Phew... That was scary.","TWN":"哈啊……嚇我一跳。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"큰소리 친 건 좋은데 이제 어떡하게.","JPN":"自信満々に答えたのはいいけど、これからどうするの？","ENG":"Okay, so you managed to get us off the hook for now. But what are we going to do?","TWN":"大話已經說了，現在怎麼辦？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"일이 잘못되면 우리까지 솎아지게 생겼잖아.","JPN":"下手したら私たちまで摘み取られる羽目になりそうじゃない。","ENG":"If we screw up, we'll be the ones getting plucked out next.","TWN":"如果事情搞砸了，估計死的就是我們了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래요. 그러니 한 번의 실수도 없도록 철저하게 준비해야죠.","JPN":"そうですね。これからは一切のミスも許されません。準備に徹底しないと。","ENG":"Indeed. That is why we must prepare thoroughly this time. There can be no mistakes.","TWN":"是啊，所以要做好萬全準備，絕對不能再失手了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 배신자와 같은 취급을 당할 수는 없으니까요.","JPN":"あの裏切り者と同じ扱いにされては困ります。","ENG":"We can't afford to be treated like that traitor.","TWN":"不能讓頭目認為，我們和那個叛徒是一樣的貨色。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};